import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import * as XLSX from 'xlsx';
import { saveAs } from 'file-saver';

function Present_Absent(){



  const [absents, setAbsents] = useState([]);
  const [presents, setPresents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState(new Date());

  function formatDate(date) {
    const jj = String(date.getDate()).padStart(2, '0');
    const m = String(date.getMonth() + 1).padStart(1, '0');
    const yy = String(date.getFullYear()).slice(2);
    return `${jj}-${m}-${yy}`;
  }

  useEffect(() => {
    async function fetchData() {
      setLoading(true);
      const formattedDate = formatDate(selectedDate);

      const { data: users, error: usersError } = await supabase
        .from('USERRINFO')
        .select('USERID, Name, TITLE');

      if (usersError) {
        console.error('Erreur Userinfo:', usersError.message);
        setLoading(false);
        return;
      }

      const { data: runData, error: runError } = await supabase
        .from('USER_OF_RUN')
        .select('USERID, STARTDATE');

      if (runError) {
        console.error('Erreur USER_OF_RUN:', runError.message);
        setLoading(false);
        return;
      }

      const presentUserIds = new Set(
        runData
          .filter((r) => {
            if (!r.STARTDATE) return false;
            const dateStr = formatDate(new Date(r.STARTDATE));
            return dateStr === formattedDate;
          })
          .map((r) => r.USERID)
      );

      const présents = users.filter((user) => presentUserIds.has(user.USERID));
      const absents = users.filter((user) => !presentUserIds.has(user.USERID));

      setPresents(présents);
      setAbsents(absents);
      setLoading(false);
    }

    fetchData();
  }, [selectedDate]);

  const exportToExcel = (list, label) => {
    if (!list || list.length === 0) return;

    const exportData = list.map((user) => ({
      UserID: user.USERID,
      Nom: user.Name,
      Titre: user.TITLE,
    }));

    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, label);

    const excelBuffer = XLSX.write(workbook, { bookType: 'xlsx', type: 'array' });
    const blob = new Blob([excelBuffer], { type: 'application/octet-stream' });
    saveAs(blob, `${label.toLowerCase()}_${formatDate(selectedDate)}.xlsx`);
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>Présence des utilisateurs</h2>

      <label>
        Choisir une date :{" "}
        <input
          type="date"
          value={selectedDate.toISOString().substring(0, 10)}
          onChange={(e) => setSelectedDate(new Date(e.target.value))}
        />
      </label>

      {loading ? (
        <p>Chargement...</p>
      ) : (
        <>
          {/* ✔ PRÉSENTS */}
          <h3>✔ Présents ({presents.length})</h3>
          {presents.length === 0 ? (
            <p>Aucun utilisateur présent ce jour-là.</p>
          ) : (
            <>
              <button
                onClick={() => exportToExcel(presents, 'Presents')}
                style={{ marginBottom: '10px', padding: '6px 12px' }}
              >
                📥 Exporter les présents en Excel
              </button>

              <table border="1" cellPadding="8" cellSpacing="0" style={{ marginBottom: '30px' }}>
                <thead>
                  <tr>
                    <th>UserID</th>
                    <th>Nom</th>
                    <th>Titre</th>
                  </tr>
                </thead>
                <tbody>
                  {presents.map((user) => (
                    <tr key={user.USERID}>
                      <td>{user.USERID}</td>
                      <td>{user.Nom}</td>
                      <td>{user.TITLE}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}

          {/* ❌ ABSENTS */}
          <h3>❌ Absents ({absents.length})</h3>
          {absents.length === 0 ? (
            <p>Tous les utilisateurs sont présents 🎉</p>
          ) : (
            <>
              <button
                onClick={() => exportToExcel(absents, 'Absents')}
                style={{ marginBottom: '10px', padding: '6px 12px' }}
              >
                📥 Exporter les absents en Excel
              </button>

              <table border="1" cellPadding="8" cellSpacing="0">
                <thead>
                  <tr>
                    <th>UserID</th>
                    <th>Nom</th>
                    <th>Titre</th>
                  </tr>
                </thead>
                <tbody>
                  {absents.map((user) => (
                    <tr key={user.USERID}>
                      <td>{user.USERID}</td>
                      <td>{user.Nom}</td>
                      <td>{user.TITLE}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}
        </>
      )}
    </div>
  );
}



export default Present_Absent
